content.text:
terraform {
  required_version = ">= 1.8"

  required_providers {
    hcloud = {
      source  = "hetznercloud/hcloud"
      version = "~> 1.50.0"
    }
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "hcloud" {
  token = var.hcloud_token
}

provider "aws" {
  alias  = "hetzner_s3"
  region = "fsn1"

  access_key = var.s3_access_key
  secret_key = var.s3_secret_key

  endpoints {
    s3 = var.s3_endpoint
  }

  skip_credentials_validation = true
  skip_metadata_api_check     = true
  skip_region_validation      = true
  skip_requesting_account_id  = true
  s3_use_path_style           = true
}

variable "hcloud_token" {
  description = "Hetzner Cloud API token"
  type        = string
  sensitive   = true
}

variable "ssh_public_key" {
  description = "SSH public key for server access"
  type        = string
}

variable "admin_ip" {
  description = "Admin IP address for SSH access (CIDR notation)"
  type        = string
}

variable "server_location" {
  description = "Hetzner datacenter location"
  type        = string
  default     = "fsn1"
}

variable "s3_access_key" {
  description = "Hetzner Object Storage access key"
  type        = string
  sensitive   = true
}

variable "s3_secret_key" {
  description = "Hetzner Object Storage secret key"
  type        = string
  sensitive   = true
}

variable "s3_endpoint" {
  description = "Hetzner Object Storage endpoint"
  type        = string
  default     = "https://fsn1.your-objectstorage.com"
}

resource "hcloud_firewall" "web" {
  name = "attento-web"

  rule {
    direction   = "in"
    protocol    = "tcp"
    port        = "22"
    source_ips  = [var.admin_ip]
    description = "SSH"
  }

  rule {
    direction   = "in"
    protocol    = "tcp"
    port        = "80"
    source_ips  = ["0.0.0.0/0", "::/0"]
    description = "HTTP"
  }

  rule {
    direction   = "in"
    protocol    = "tcp"
    port        = "443"
    source_ips  = ["0.0.0.0/0", "::/0"]
    description = "HTTPS"
  }

  rule {
    direction   = "in"
    protocol    = "icmp"
    source_ips  = ["0.0.0.0/0", "::/0"]
    description = "ICMP"
  }

  apply_to {
    label_selector = "app=attento"
  }
}

resource "aws_s3_bucket" "backups" {
  provider = aws.hetzner_s3
  bucket   = "attento-backups"
}

resource "aws_s3_bucket_versioning" "backups" {
  provider = aws.hetzner_s3
  bucket   = aws_s3_bucket.backups.id

  versioning_configuration {
    status = "Enabled"
  }
}

output "server_ip" {
  description = "Public IPv4 address of the web server"
  value       = hcloud_server.web.ipv4_address
}

output "server_ipv6" {
  description = "Public IPv6 address of the web server"
  value       = hcloud_server.web.ipv6_address
}

output "s3_bucket" {
  description = "S3 bucket for Litestream backups"
  value       = aws_s3_bucket.backups.bucket
}

output "next_steps" {
  description = "Next steps after provisioning"
  value       = <<-EOT
    1. Update DNS: app.attento-health.com -> ${hcloud_server.web.ipv4_address}
    2. Update config/deploy.yml with server IP
    3. Run: infra/bin/provision --config  (configure server with Ansible)
    4. Run: infra/bin/provision --deploy  (bootstrap Kamal)
  EOT
}

arguments.content:
terraform {
  required_version = ">= 1.8"

  required_providers {
    digitalocean = {
      source  = "digitalocean/digitalocean"
      version = "~> 2.0"
    }
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
  }
}

provider "digitalocean" {
  token = var.do_token
}

# DO Spaces is S3-compatible. The AWS provider lets us manage the bucket as
# infrastructure. Use the region-specific endpoint (e.g. nyc3).
provider "aws" {
  alias  = "spaces"

  region = var.spaces_region

  access_key = var.spaces_access_key_id
  secret_key = var.spaces_secret_access_key

  endpoints {
    s3 = "https://${var.spaces_region}.digitaloceanspaces.com"
  }

  skip_credentials_validation = true
  skip_metadata_api_check     = true
  skip_region_validation      = true
  skip_requesting_account_id  = true
  s3_use_path_style           = true
}

variable "do_token" {
  description = "DigitalOcean API token (read/write)"
  type        = string
  sensitive   = true
}

variable "ssh_public_key" {
  description = "SSH public key for Droplet access"
  type        = string
}

variable "admin_ip" {
  description = "Admin IP/CIDR allowed SSH access. Do NOT use 0.0.0.0/0 in production."
  type        = string
}

variable "droplet_region" {
  description = "DigitalOcean region slug"
  type        = string
  default     = "nyc3"
}

variable "droplet_size" {
  description = "Droplet size slug"
  type        = string
  default     = "s-2vcpu-4gb"
}

variable "project_name" {
  description = "Used for resource naming and tags"
  type        = string
  default     = "reviewlens"
}

variable "spaces_region" {
  description = "DO Spaces region"
  type        = string
  default     = "nyc3"
}

variable "spaces_access_key_id" {
  description = "DO Spaces access key (for backup bucket)"
  type        = string
  sensitive   = true
}

variable "spaces_secret_access_key" {
  description = "DO Spaces secret key (for backup bucket)"
  type        = string
  sensitive   = true
}

# Firewall: SSH restricted to the admin IP, HTTP/HTTPS open to the world.
# Postgres is intentionally NOT opened, it is bound to 127.0.0.1 in deploy.yml.
resource "digitalocean_firewall" "web" {
  name = "${var.project_name}-web"

  droplet_ids = [digitalocean_droplet.web.id]

  inbound_rule {
    protocol         = "tcp"
    port_policy      = "22"
    source_addresses = [var.admin_ip]
  }

  inbound_rule {
    protocol         = "tcp"
    port_policy      = "80"
    source_addresses = ["0.0.0.0/0", "::/0"]
  }

  inbound_rule {
    protocol         = "tcp"
    port_policy      = "443"
    source_addresses = ["0.0.0.0/0", "::/0"]
  }

  inbound_rule {
    protocol         = "icmp"
    source_addresses = ["0.0.0.0/0", "::/0"]
  }

  outbound_rule {
    protocol              = "tcp"
    port_policy           = "all"
    destination_addresses = ["0.0.0.0/0", "::/0"]
  }

  outbound_rule {
    protocol              = "udp"
    port_policy           = "all"
    destination_addresses = ["0.0.0.0/0", "::/0"]
  }

  outbound_rule {
    protocol              = "icmp"
    destination_addresses = ["0.0.0.0/0", "::/0"]
  }
}

# DO Spaces bucket for pg_dump backups. PostgreSQL cannot use Litestream
# (SQLite-only), so we ship compressed pg_dump archives to Spaces instead
# (see infra/ansible/files/pg_backup.sh, run via cron on the Droplet).
resource "aws_s3_bucket" "backups" {
  provider = aws.spaces
  bucket   = "${var.project_name}-backups"
}

resource "aws_s3_bucket_versioning" "backups" {
  provider = aws.spaces
  bucket   = aws_s3_bucket.backups.id

  versioning_configuration {
    status = "Enabled"
  }
}

# Expire daily backups after 30 days; keep weekly snapshots longer via versions.
resource "aws_s3_bucket_lifecycle_configuration" "backups" {
  provider = aws.spaces
  bucket   = aws_s3_bucket.backups.id

  rule {
    id     = "expire-dumps"
    status = "Enabled"

    expiration {
      days = 30
    }

    noncurrent_version_expiration {
      noncurrent_days = 7
    }
  }
}

output "server_ip" {
  description = "Public IPv4 of the web Droplet"
  value       = digitalocean_droplet.web.ipv4_address
}

output "server_ipv6" {
  description = "Public IPv6 of the web Droplet"
  value       = digitalocean_droplet.web.ipv6_address
}

output "backups_bucket" {
  description = "DO Spaces bucket for Postgres backups"
  value       = aws_s3_bucket.backups.bucket
}

output "next_steps" {
  description = "Next steps after provisioning"
  value       = <<-EOT
    1. Point DNS: ${var.project_name} domain -> ${digitalocean_droplet.web.ipv4_address}
    2. Run: infra/bin/provision --config   (Ansible: harden + Docker + backup cron)
    3. Set env then run: infra/bin/provision --deploy   (kamal setup)
       export DEPLOY_HOST=${digitalocean_droplet.web.ipv4_address}
       export DEPLOY_DOMAIN=<your-domain>
  EOT
}

SPACES_ACCESS_KEY_ID={{ spaces_access_key_id }}
SPACES_SECRET_ACCESS_KEY={{ spaces_secret_access_key }}
SPACES_REGION={{ spaces_region }}
SPACES_BUCKET={{ backup_bucket }}
REVIEWLENS_DB_PASSWORD={{ db_password }}
REVIEWLENS_DB_USER={{ db_user | default('review_lens') }}
REVIEWLENS_DB_NAME={{ db_name | default('review_lens_production') }}

